// One document can hold a whole aggregate (order + items + shipping)
{
  _id: ObjectId("66..."),
  customerId: ObjectId("55..."),     // reference to another collection
  status: "shipped",
  total: 4299,                       // cents
  items: [                           // embedded array of sub-documents
    { sku: "PLQ-PRO", qty: 1, price: 3000 },
    { sku: "NFC-CARD", qty: 2, price: 649 }
  ],
  shipping: {                        // embedded sub-document
    address: "12 Rue de Paris",
    carrier: "DHL"
  },
  createdAt: ISODate("2026-06-25T10:00:00Z")
}

// Query inside the document and into arrays:
db.orders.find({ status: "shipped", "items.sku": "PLQ-PRO" })
db.orders.updateOne({ _id: id }, { $set: { status: "delivered" } })

// Total revenue per customer for shipped orders in 2026, top 5 spenders
db.orders.aggregate([
  // 1) filter early - $match before $group shrinks the stream and can use an index
  { $match: {
      status: "shipped",
      createdAt: { $gte: ISODate("2026-01-01"), $lt: ISODate("2027-01-01") }
  }},
  // 2) group by customer, summing totals and counting orders
  { $group: {
      _id: "$customerId",
      revenue: { $sum: "$total" },
      orders:  { $sum: 1 }
  }},
  // 3) sort by revenue descending
  { $sort: { revenue: -1 } },
  // 4) keep the top 5
  { $limit: 5 },
  // 5) join customer details (left outer join on the customers collection)
  { $lookup: {
      from: "customers", localField: "_id",
      foreignField: "_id", as: "customer"
  }},
  // 6) reshape the output
  { $project: {
      _id: 0, customerId: "$_id", revenue: 1, orders: 1,
      name: { $arrayElemAt: ["$customer.name", 0] }
  }}
])

challenges.solutionCode:
// users collection - referenced by orders/reviews via _id
{ _id: ObjectId("u1"), email: "a@b.com", name: "Alice", createdAt: ISODate(...) }

// products collection - product facts + a small denormalized rating summary
{ _id: ObjectId("p1"), sku: "PLQ-PRO", name: "Plaque Pro",
  price: 3000, ratingAvg: 4.6, ratingCount: 128 }   // summary, not the reviews themselves

// orders collection - EMBED line items (bounded, read together, atomic with the order)
{ _id: ObjectId("o1"),
  userId: ObjectId("u1"),          // REFERENCE the user (own lifecycle)
  status: "shipped",
  total: 4299,
  items: [                          // embedded: 1-to-few, owned by the order
    { productId: ObjectId("p1"), sku: "PLQ-PRO", qty: 1, price: 3000 },
    { productId: ObjectId("p2"), sku: "NFC-CARD", qty: 2, price: 649 }
  ],
  createdAt: ISODate("2026-06-25T10:00:00Z") }

// reviews collection - REFERENCE (unbounded per product => separate collection)
{ _id: ObjectId("r1"), productId: ObjectId("p1"), userId: ObjectId("u1"),
  rating: 5, body: "Great quality", createdAt: ISODate(...) }

// Indexes that match the access patterns:
db.users.createIndex({ email: 1 }, { unique: true });        // login lookup
db.orders.createIndex({ userId: 1, createdAt: -1 });          // a user's orders, newest first
db.orders.createIndex({ status: 1, createdAt: -1 });          // ops dashboards
db.reviews.createIndex({ productId: 1, createdAt: -1 });      // paginate a product's reviews
db.products.createIndex({ sku: 1 }, { unique: true });

db.orders.aggregate([
  // 1) $match FIRST: filter by status + date range so an index on
  //    { status: 1, createdAt: 1 } can serve it before any grouping.
  { $match: {
      status: { $in: ["shipped", "delivered"] },
      createdAt: { $gte: ISODate("2026-01-01"), $lt: ISODate("2027-01-01") }
  }},
  // 2) group by calendar month; sum revenue and count orders
  { $group: {
      _id: { month: { $month: "$createdAt" } },
      revenue: { $sum: "$total" },
      orders:  { $sum: 1 }
  }},
  // 3) sort chronologically by month
  { $sort: { "_id.month": 1 } },
  // 4) reshape into a clean output shape
  { $project: {
      _id: 0,
      month: "$_id.month",
      revenue: 1,
      orders: 1,
      avgOrderValue: { $round: [ { $divide: ["$revenue", "$orders"] }, 0 ] }
  }}
]);

// Supporting index so stage 1 is an index scan, not a COLLSCAN:
db.orders.createIndex({ status: 1, createdAt: 1 });
